import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useNavigate } from "react-router-dom";

export default function EditProfile() {
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [name, setName] = useState("");

  const [imageFile, setImageFile] = useState(null);
  const [preview, setPreview] = useState("");

  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("user"));

    axios
      .get(`http://localhost:8086/user/by-email/${stored.email}`)
      .then((res) => {
        setUser(res.data);
        setName(res.data.name);
        setPreview(res.data.profileImage);
      });
  }, []);

  // ✅ handle image select
  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setImageFile(file);

    // preview
    const reader = new FileReader();
    reader.onloadend = () => {
      setPreview(reader.result);
    };
    reader.readAsDataURL(file);
  };

  // ✅ UPDATE PROFILE WITH IMAGE
  const handleUpdateProfile = async () => {
    try {
      const formData = new FormData();
      formData.append("email", user.email);
      formData.append("name", name);

      if (imageFile) {
        formData.append("image", imageFile);
      }

      const res = await axios.put(
        "http://localhost:8086/user/update-profile",
        formData,
        {
          headers: {
            "Content-Type": "multipart/form-data",
          },
        }
      );

      Swal.fire("Success", res.data.message, "success");

      localStorage.setItem(
        "user",
        JSON.stringify({
          ...user,
          name,
          profileImage: res.data.profileImage,
        })
      );

      navigate("/profile");
    } catch (err) {
      Swal.fire("Error", err.response?.data || "Update failed", "error");
    }
  };

  // password unchanged
  const handleChangePassword = async () => {
    try {
      await axios.put("http://localhost:8086/user/change-password", {
        email: user.email,
        currentPassword,
        newPassword,
      });

      Swal.fire("Success", "Password updated", "success");
      setCurrentPassword("");
      setNewPassword("");
    } catch (err) {
      Swal.fire("Error", "Password update failed", "error");
    }
  };

  if (!user) return <div>Loading...</div>;

  return (
    <div className="min-h-screen bg-gray-100 flex justify-center p-6">
      <div className="bg-white p-6 rounded-xl shadow w-full max-w-lg">

        <h2 className="text-xl font-bold mb-4">Edit Profile</h2>

        {/* NAME */}
        <input
          className="w-full border p-2 mb-3 rounded"
          value={name}
          onChange={(e) => setName(e.target.value)}
        />

        {/* IMAGE UPLOAD */}
        <input
          type="file"
          accept="image/*"
          onChange={handleImageChange}
          className="w-full mb-3"
        />

        {/* PREVIEW */}
        {preview && (
          <img
            src={preview}
            alt="preview"
            className="w-24 h-24 rounded-full mx-auto mb-4 object-cover"
          />
        )}

        {/* SAVE */}
        <button
          onClick={handleUpdateProfile}
          className="w-full bg-green-600 text-white py-2 rounded mb-6"
        >
          Save Changes
        </button>

        <hr className="my-4" />

        {/* PASSWORD */}
        <input
          type="password"
          placeholder="Current Password"
          className="w-full border p-2 mb-2 rounded"
          value={currentPassword}
          onChange={(e) => setCurrentPassword(e.target.value)}
        />

        <input
          type="password"
          placeholder="New Password"
          className="w-full border p-2 mb-3 rounded"
          value={newPassword}
          onChange={(e) => setNewPassword(e.target.value)}
        />

        <button
          onClick={handleChangePassword}
          className="w-full bg-indigo-600 text-white py-2 rounded"
        >
          Change Password
        </button>

      </div>
    </div>
  );
}
